  // Horizontal drag scrolling
  const handleScrollMouseDown = (e) => {
    if (e.target.closest('.person-card') || e.target.closest('button') || e.target.closest('input')) {
      return; // Don't drag if clicking on person cards, buttons, or inputs
    }
    setIsDraggingScroll(true);
    setScrollStart({
      x: e.pageX,
      scrollLeft: scrollContainerRef.current.scrollLeft
    });
  };

  const handleScrollMouseMove = (e) => {
    if (!isDraggingScroll) return;
    e.preventDefault();
    const x = e.pageX;
    const walk = (scrollStart.x - x) * 2; // Multiply for faster scrolling
    scrollContainerRef.current.scrollLeft = scrollStart.scrollLeft + walk;
  };

  const handleScrollMouseUp = () => {
    setIsDraggingScroll(false);
  };

  React.useEffect(() => {
    if (isDraggingScroll) {
      document.addEventListener('mousemove', handleScrollMouseMove);
      document.addEventListener('mouseup', handleScrollMouseUp);
      return () => {
        document.removeEventListener('mousemove', handleScrollMouseMove);
        document.removeEventListener('mouseup', handleScrollMouseUp);
      };
    }
  }, [isDraggingScroll, scrollStart]);

  // Position colour bars precisely between the header and footer keylines
  React.useEffect(() => {
    const positionBars = () => {
      const cards = document.querySelectorAll('[data-department-id]');
      cards.forEach(card => {
        const bar = card.querySelector('[data-color-bar]');
        const header = card.querySelector('[data-header-keyline]');
        const footer = card.querySelector('[data-footer-keyline]');
        if (!bar || !header || !footer) return;
        const cardRect = card.getBoundingClientRect();
        const headerRect = header.getBoundingClientRect();
        const footerRect = footer.getBoundingClientRect();
        const top = headerRect.bottom - cardRect.top;
        const bottom = cardRect.bottom - footerRect.top;
        bar.style.top = `${top}px`;
        bar.style.bottom = `${bottom}px`;
      });
    };
    positionBars();
    window.addEventListener('resize', positionBars);
    return () => window.removeEventListener('resize', positionBars);
  }, [departments, people]);

